137→function isMissingDbObjectError(error: unknown): boolean {
138→  const pg = error as { code?: unknown; message?: unknown } | null;
139→  const code = typeof pg?.code === "string" ? pg.code : "";
140→  if (code === "42P01" || code === "42703") return true;
141→  const message = typeof pg?.message === "string" ? pg.message.toLowerCase() : "";
142→  return message.includes("does not exist") || message.includes("undefined column") || message.includes("undefined table");
143→}
144→
145→function isUniqueViolationError(error: unknown): boolean {
146→  const pg = error as { code?: unknown } | null;
147→  return pg?.code === "23505";
148→}
