163→function sanitizeDetailsForContentHash(details: SubmissionDetails): Record<string, unknown> {
164→  const out: Record<string, unknown> = {};
165→  for (const [key, value] of Object.entries(details ?? {})) {
166→    if (HASH_DETAIL_OMIT_KEYS.has(key)) continue;
167→    out[key] = value;
168→  }
169→  return out;
170→}
