180→export function computeEventContentHash(input: {
181→  pointId: string;
182→  category: SubmissionCategory;
183→  eventType: PointEventType;
184→  location: SubmissionLocation;
185→  details: SubmissionDetails;
186→}): string {
187→  const stablePayload = {
188→    pointId: input.pointId,
189→    category: input.category,
190→    eventType: input.eventType,
191→    latitude: Number(input.location.latitude.toFixed(6)),
192→    longitude: Number(input.location.longitude.toFixed(6)),
193→    details: sanitizeDetailsForContentHash(input.details),
194→  };
195→  return hashText(JSON.stringify(stableSort(stablePayload)));
196→}
