230→async function getUserVelocityCount(userId: string): Promise<number> {
231→  const result = await query<{ count: number }>(
232→    `SELECT COUNT(*)::int AS count
233→     FROM point_events
234→     WHERE user_id = $1
235→       AND created_at > NOW() - make_interval(mins => $2::int)`,
236→    [userId, VELOCITY_WINDOW_MINUTES],
237→  );
238→  return toInt(result.rows[0]?.count, 0);
