317→async function getUserRiskStats(userId: string): Promise<{ accountAgeDays: number; totalSubmissions: number; priorFraudFlags: number }> {
318→  let accountAgeDays = 0;
319→  try {
320→    const accountResult = await query<{ account_age_days: number }>(
321→      `SELECT EXTRACT(EPOCH FROM (NOW() - COALESCE(created_at, NOW()))) / 86400.0 AS account_age_days
322→       FROM user_profiles
323→       WHERE id = $1
324→       LIMIT 1`,
325→      [userId],
326→    );
327→    accountAgeDays = toNumber(accountResult.rows[0]?.account_age_days, 0);
328→  } catch (error) {
329→    if (!isMissingDbObjectError(error)) throw error;
330→  }
331→
332→  const totalResult = await query<{ total: number }>(
333→    `SELECT COUNT(*)::int AS total FROM point_events WHERE user_id = $1`,
334→    [userId],
335→  );
336→  const totalSubmissions = toInt(totalResult.rows[0]?.total, 0);
337→
338→  let priorFraudFlags = 0;
339→  try {
340→    const fraudResult = await query<{ total: number }>(
341→      `SELECT COUNT(*)::int AS total
342→       FROM fraud_audit_log
343→       WHERE user_id = $1
344→         AND action IN ('flagged', 'blocked')`,
