417→export async function evaluateSubmissionRisk(input: SubmissionRiskInput): Promise<SubmissionRiskEvaluation> {
418→  const imageHash = computeImageSha256(input.imageBuffer);
419→  const contentHash = computeEventContentHash({
420→    pointId: input.pointId,
421→    category: input.category,
422→    eventType: input.eventType,
423→    location: input.finalLocation,
424→    details: input.details,
425→  });
426→
427→  const [
428→    userVelocity,
429→    lastSubmission,
430→    duplicateMatches,
431→    userRiskStats,
432→    selfEnrichment,
433→    deviceVelocity,
434→    ipVelocity,
435→  ] = await Promise.all([
436→    getUserVelocityCount(input.userId),
437→    getLastSubmissionByUser(input.userId),
438→    getDuplicateImageMatches(imageHash),
439→    getUserRiskStats(input.userId),
440→    getSelfEnrichmentStats(input.userId, input.pointId),
441→    input.clientDevice?.deviceId ? getDeviceVelocityStats(input.clientDevice.deviceId) : Promise.resolve({ count: 0, distinctUsers: 0 }),
442→    input.ipHash ? getIpVelocityStats(input.ipHash) : Promise.resolve({ count: 0, distinctUsers: 0 }),
443→  ]);
444→
445→  const reviewFlags = new Set<string>();
446→  const blockingCodes = new Set<string>();
447→
448→  let locationRisk = 0;
449→  if (!input.submissionLocation) locationRisk += 15;
450→  if (!input.photoMetadata.gps) locationRisk += 20;
451→  if (!input.ipLocation) locationRisk += 10;
452→
453→  if (input.submissionLocation && input.photoMetadata.gps) {
454→    const distance = haversineKm(input.submissionLocation, input.photoMetadata.gps);
455→    if (distance > 1) {
456→      locationRisk += 40;
457→      reviewFlags.add("gps_mismatch");
458→    } else if (distance > 0.5) {
459→      locationRisk += 15;
460→      reviewFlags.add("gps_marginal_match");
461→    }
462→  }
463→
464→  if (input.ipLocation && input.photoMetadata.gps) {
465→    const ipDistance = haversineKm(input.ipLocation, input.photoMetadata.gps);
466→    if (ipDistance > 50) {
467→      locationRisk += 30;
468→      reviewFlags.add("ip_photo_mismatch");
469→    } else if (ipDistance > 20) {
470→      locationRisk += 10;
471→      reviewFlags.add("ip_photo_marginal_match");
472→    }
473→  }
474→
475→  if (input.ipReputation?.isDatacenter || input.ipReputation?.isVpn) {
476→    locationRisk += 10;
477→    reviewFlags.add("suspicious_ip_org");
478→  }
479→  if (input.ipReputation?.isTor) {
480→    locationRisk += 40;
481→    blockingCodes.add("tor_exit_ip");
482→  }
483→  locationRisk = Math.min(100, locationRisk);
484→
485→  let photoRisk = 0;
486→  if (!input.photoMetadata.gps) photoRisk += 15;
487→  if (!input.photoMetadata.capturedAt) photoRisk += 10;
488→  if (!input.photoMetadata.deviceMake) photoRisk += 10;
489→  if (!input.photoMetadata.deviceModel) photoRisk += 10;
490→
491→  const duplicateForDifferentPoint = duplicateMatches.some((row) => row.pointId !== input.pointId);
492→  if (duplicateForDifferentPoint) {
493→    photoRisk += 80;
494→    blockingCodes.add("duplicate_photo");
495→  }
496→  const duplicateForSamePoint = duplicateMatches.some((row) => row.pointId === input.pointId);
497→  if (duplicateForSamePoint) {
498→    reviewFlags.add("duplicate_photo_same_point");
499→    photoRisk += 25;
500→  }
501→
502→  if (input.clientDevice?.isLowEnd && photoRisk > 0 && photoRisk <= 35) {
503→    photoRisk = Math.max(0, photoRisk - 10);
504→  }
505→  photoRisk = Math.min(100, photoRisk);
506→
507→  let temporalRisk = 0;
508→  if (userVelocity >= USER_VELOCITY_BLOCK_THRESHOLD) {
509→    temporalRisk += 60;
510→    blockingCodes.add("velocity_limit");
511→  } else if (userVelocity >= USER_VELOCITY_FLAG_THRESHOLD) {
512→    temporalRisk += 30;
513→    reviewFlags.add("high_user_velocity");
514→  } else if (userVelocity >= 3) {
515→    temporalRisk += 10;
516→  }
517→
518→  if (deviceVelocity.count >= DEVICE_VELOCITY_FLAG_THRESHOLD) {
519→    temporalRisk += 15;
520→    reviewFlags.add("high_device_velocity");
521→  }
522→  if (deviceVelocity.distinctUsers >= 2) {
523→    temporalRisk += 10;
524→    reviewFlags.add("shared_device");
525→  }
526→
527→  if (ipVelocity.count >= IP_VELOCITY_FLAG_THRESHOLD) {
528→    temporalRisk += 10;
529→    reviewFlags.add("high_ip_velocity");
530→  }
531→  if (ipVelocity.distinctUsers >= 3) {
532→    temporalRisk += 10;
533→    reviewFlags.add("shared_ip");
534→  }
535→
536→  let impossibleTravelSpeedKmh: number | null = null;
537→  if (lastSubmission) {
538→    const distanceKm = haversineKm(lastSubmission.location, input.finalLocation);
539→    const elapsedHours =
540→      (Date.now() - new Date(lastSubmission.createdAt).getTime()) / (1000 * 60 * 60);
541→    if (elapsedHours > 0) {
542→      impossibleTravelSpeedKmh = distanceKm / elapsedHours;
543→      if (impossibleTravelSpeedKmh > IMPOSSIBLE_TRAVEL_BLOCK_KMH) {
544→        temporalRisk += 50;
545→        blockingCodes.add("impossible_travel");
546→      } else if (impossibleTravelSpeedKmh > IMPOSSIBLE_TRAVEL_FLAG_KMH) {
547→        temporalRisk += 25;
548→        reviewFlags.add("impossible_travel");
549→      }
550→    }
551→  }
552→  temporalRisk = Math.min(100, temporalRisk);
553→
554→  let userRisk = 0;
555→  if (userRiskStats.accountAgeDays < 1) userRisk += 25;
556→  else if (userRiskStats.accountAgeDays < 7) userRisk += 15;
557→  else if (userRiskStats.accountAgeDays < 30) userRisk += 5;
558→
559→  if (userRiskStats.totalSubmissions === 0) userRisk += 15;
560→  else if (userRiskStats.totalSubmissions < 5) userRisk += 8;
561→
562→  if (userRiskStats.priorFraudFlags >= 5) {
563→    userRisk += 40;
564→    reviewFlags.add("repeat_fraud_pattern");
565→  } else if (userRiskStats.priorFraudFlags >= 1) {
566→    userRisk += 20;
567→    reviewFlags.add("historical_fraud_flags");
568→  }
569→  userRisk = Math.min(100, userRisk);
570→
571→  let behavioralRisk = 0;
572→  if (input.eventType === "ENRICH_EVENT" && selfEnrichment.ownsPoint) {
573→    behavioralRisk += 20;
574→    reviewFlags.add("self_enrichment");
575→    if (selfEnrichment.recentSelfEnrichments >= 3) {
576→      behavioralRisk += 25;
577→      reviewFlags.add("self_enrichment_loop");
578→    }
579→    if (selfEnrichment.recentSelfEnrichments >= 5) {
580→      blockingCodes.add("velocity_limit");
581→    }
582→  }
583→
584→  const plausibility = evaluateFieldPlausibility(input.category, input.details);
585→  if (plausibility.block) {
586→    blockingCodes.add(plausibility.block);
587→  }
588→  for (const flag of plausibility.flags) reviewFlags.add(flag);
589→
590→  const exifTrustScore = computeExifTrustScore({
591→    gps: input.photoMetadata.gps,
592→    capturedAt: input.photoMetadata.capturedAt,
593→    deviceMake: input.photoMetadata.deviceMake,
594→    deviceModel: input.photoMetadata.deviceModel,
595→    isLowEnd: input.clientDevice?.isLowEnd === true,
596→  });
597→
598→  if (exifTrustScore < EXIF_TRUST_FLAG_THRESHOLD) {
599→    reviewFlags.add("low_exif_trust");
600→    behavioralRisk += exifTrustScore < 40 ? 25 : 10;
601→    if (exifTrustScore < 40 && !input.hasSecondaryPhoto) {
602→      reviewFlags.add("secondary_photo_recommended");
603→    }
604→  }
605→
606→  behavioralRisk = Math.min(100, behavioralRisk);
607→
608→  const riskComponents: RiskComponents = {
609→    locationRisk,
610→    photoRisk,
611→    temporalRisk,
612→    userRisk,
613→    behavioralRisk,
614→  };
615→
616→  const riskScore = buildRiskScore(riskComponents);
617→  const shouldReview = reviewFlags.size > 0 || riskScore >= REVIEW_RISK_THRESHOLD;
618→
619→  if (input.isAdmin && blockingCodes.size > 0) {
620→    for (const code of blockingCodes) {
621→      reviewFlags.add(`admin_bypass_${code}`);
622→    }
623→    reviewFlags.add("admin_bypass");
624→    blockingCodes.clear();
625→  }
626→
627→  const firstBlockCode = blockingCodes.values().next().value ?? null;
628→  const block = firstBlockCode ? blockDetailsForCode(firstBlockCode) : null;
629→
630→  return {
631→    shouldBlock: Boolean(firstBlockCode),
632→    blockCode: firstBlockCode,
633→    blockReason: block?.reason ?? null,
634→    imageHash,
635→    contentHash,
636→    reviewStatus: shouldReview ? "pending_review" : "auto_approved",
637→    reviewFlags: Array.from(reviewFlags),
638→    riskScore,
639→    exifTrustScore,
640→    velocity: {
641→      user15m: userVelocity,
642→      device15m: input.clientDevice?.deviceId ? deviceVelocity.count : null,
643→      ip15m: input.ipHash ? ipVelocity.count : null,
644→      deviceDistinctUsers15m: input.clientDevice?.deviceId ? deviceVelocity.distinctUsers : null,
645→      ipDistinctUsers15m: input.ipHash ? ipVelocity.distinctUsers : null,
646→    },
647→    impossibleTravelSpeedKmh,
648→    riskComponents,
649→  };
650→}
