265→function extractGps(parsed: Record<string, unknown>): SubmissionLocation | null {
266→  const direct =
267→    toGpsLocation(parsed.latitude, parsed.longitude) ??
268→    toGpsLocation(parsed.lat, parsed.lon) ??
269→    toGpsLocation(parsed.lat, parsed.lng);
270→  if (direct) return direct;
271→
272→  const gpsContainer = parsed.gps && typeof parsed.gps === "object" ? (parsed.gps as Record<string, unknown>) : null;
273→  if (gpsContainer) {
274→    const nested =
275→      toGpsLocation(gpsContainer.latitude, gpsContainer.longitude) ??
276→      toGpsLocation(gpsContainer.lat, gpsContainer.lon) ??
277→      toGpsLocation(gpsContainer.lat, gpsContainer.lng);
278→    if (nested) return nested;
279→  }
280→
281→  const rawLatitude = parseDmsCoordinate(parsed.GPSLatitude ?? gpsContainer?.GPSLatitude);
282→  const rawLongitude = parseDmsCoordinate(parsed.GPSLongitude ?? gpsContainer?.GPSLongitude);
283→  if (rawLatitude === null || rawLongitude === null) return null;
284→
285→  const latitude = applyHemisphere(rawLatitude, parsed.GPSLatitudeRef ?? gpsContainer?.GPSLatitudeRef, "S");
286→  const longitude = applyHemisphere(rawLongitude, parsed.GPSLongitudeRef ?? gpsContainer?.GPSLongitudeRef, "W");
287→  return { latitude, longitude };
288→}
