335→  const mime = normalizeString(options.mime);
336→  const ext = normalizeString(options.ext);
337→  if (mime) parts.push(`mime=${mime}`);
338→  if (ext) parts.push(`ext=${ext}`);
339→  if (typeof options.byteLength === "number" && Number.isFinite(options.byteLength) && options.byteLength > 0) {
340→    parts.push(`bytes=${Math.round(options.byteLength)}`);
341→  }
342→  return parts.join("; ");
343→}
