622→export function buildPhotoFraudMetadata(params: BuildPhotoFraudMetadataParams): SubmissionPhotoMetadata | null {
623→  if (!params.extracted) return null;
624→
625→  const { extracted, submissionLocation, ipLocation, submissionMatchThresholdKm, ipMatchThresholdKm } = params;
626→  const gps = extracted.gps;
627→
628→  const submissionDistanceRaw = gps && submissionLocation ? haversineKm(submissionLocation, gps) : null;
629→  const ipDistanceRaw = gps && ipLocation ? haversineKm(ipLocation, gps) : null;
630→
631→  const submissionDistanceKm = submissionDistanceRaw === null ? null : roundKm(submissionDistanceRaw);
632→  const ipDistanceKm = ipDistanceRaw === null ? null : roundKm(ipDistanceRaw);
633→
634→  return {
635→    gps,
636→    capturedAt: extracted.capturedAt,
637→    deviceMake: extracted.deviceMake,
638→    deviceModel: extracted.deviceModel,
639→    submissionDistanceKm,
640→    submissionGpsMatch: submissionDistanceKm === null ? null : submissionDistanceKm <= submissionMatchThresholdKm,
641→    ipDistanceKm,
642→    ipGpsMatch: ipDistanceKm === null ? null : ipDistanceKm <= ipMatchThresholdKm,
643→    exifStatus: extracted.exifStatus,
644→    exifReason: extracted.exifReason,
645→    exifSource: extracted.exifSource,
646→  };
647→}
648→
649→export function buildSubmissionFraudCheck(params: BuildSubmissionFraudCheckParams): SubmissionFraudCheck {
650→  return {
651→    submissionLocation: params.submissionLocation,
652→    effectiveLocation: params.effectiveLocation,
653→    ipLocation: params.ipLocation,
654→    primaryPhoto: params.primaryPhoto,
655→    secondaryPhoto: params.secondaryPhoto,
656→    submissionMatchThresholdKm: params.submissionMatchThresholdKm,
657→    ipMatchThresholdKm: params.ipMatchThresholdKm,
658→  };
659→}
660→
661→function parsePhotoFraudMetadata(input: unknown): SubmissionPhotoMetadata | null {
662→  if (!input || typeof input !== "object") return null;
663→  const metadata = input as Record<string, unknown>;
664→
665→  const parsed: SubmissionPhotoMetadata = {
666→    gps: parseLocation(metadata.gps),
667→    capturedAt: parseDateIso(metadata.capturedAt),
668→    deviceMake: normalizeString(metadata.deviceMake),
669→    deviceModel: normalizeString(metadata.deviceModel),
670→    submissionDistanceKm: parseOptionalNumber(metadata.submissionDistanceKm),
671→    submissionGpsMatch: parseOptionalBoolean(metadata.submissionGpsMatch),
672→    ipDistanceKm: parseOptionalNumber(metadata.ipDistanceKm),
673→    ipGpsMatch: parseOptionalBoolean(metadata.ipGpsMatch),
674→    exifStatus: "missing",
675→    exifReason: normalizeString(metadata.exifReason),
676→    exifSource: parseExifSource(metadata.exifSource) ?? "none",
677→  };
678→
679→  const explicitStatus = parseExifStatus(metadata.exifStatus);
680→  if (explicitStatus) {
681→    parsed.exifStatus = explicitStatus;
682→  } else if (hasExifSignal(parsed)) {
683→    parsed.exifStatus = "ok";
684→  } else {
685→    parsed.exifStatus = "missing";
686→  }
687→
688→  return parsed;
689→}
690→
691→export function parseSubmissionFraudCheck(input: unknown): SubmissionFraudCheck | null {
692→  if (!input || typeof input !== "object") return null;
693→  const fraudCheck = input as Record<string, unknown>;
694→  const effectiveLocation = parseLocation(fraudCheck.effectiveLocation);
695→  if (!effectiveLocation) return null;
696→
697→  const submissionMatchThresholdKm =
698→    parseOptionalNumber(fraudCheck.submissionMatchThresholdKm) ?? DEFAULT_SUBMISSION_GPS_MATCH_THRESHOLD_KM;
699→  const ipMatchThresholdKm = parseOptionalNumber(fraudCheck.ipMatchThresholdKm) ?? 50;
700→
701→  return {
702→    submissionLocation: parseLocation(fraudCheck.submissionLocation),
703→    effectiveLocation,
704→    ipLocation: parseLocation(fraudCheck.ipLocation),
705→    primaryPhoto: parsePhotoFraudMetadata(fraudCheck.primaryPhoto),
706→    secondaryPhoto: parsePhotoFraudMetadata(fraudCheck.secondaryPhoto),
707→    submissionMatchThresholdKm,
708→    ipMatchThresholdKm,
709→  };
710→}
