30→export async function getAuthToken(request: Request): Promise<JWT | null> {
31→  const secret = getAuthSecret();
32→  if (!secret) return null;
33→  const cookieName = getSessionCookieName();
34→  const secureCookie = isSecureRequest();
35→  const salt = cookieName;
36→  const authHeader = request.headers.get("authorization");
37→  if (authHeader?.toLowerCase().startsWith("bearer ")) {
38→    const raw = authHeader.slice(7).trim();
39→    const decoded = await decode({ token: raw, secret, salt });
40→    return decoded ?? null;
41→  }
42→  return await getToken({ req: request, secret, salt, cookieName, secureCookie });
43→}
