45→export async function requireUser(request: Request): Promise<{ id: string; token: JWT } | null> {
46→  const token = await getAuthToken(request);
47→  if (!token) return null;
48→  const email = typeof token.email === "string" ? token.email.toLowerCase().trim() : null;
49→  const uid = (token as JWT & { uid?: unknown }).uid;
50→  const normalizedUid = typeof uid === "string" ? uid.trim() : null;
51→  const sub = typeof token.sub === "string" ? token.sub.trim() : null;
52→  const id = email || normalizedUid || sub;
53→  if (!id) return null;
54→  return { id, token };
55→}
