 44→function isCronRequestAuthorized(request: Request): boolean {
 45→  const authHeader = request.headers.get("authorization");
 46→  const cronSecret = process.env.CRON_SECRET;
 47→  return Boolean(cronSecret && authHeader === `Bearer ${cronSecret}`);
 48→}
 49→
 50→function requireCronAuthorization(request: Request): Response | null {
 51→  if (isCronRequestAuthorized(request)) return null;
 52→  return errorResponse("Unauthorized", 401);
 53→}
 54→
 55→function asErrorMessage(error: unknown): string {
 56→  return error instanceof Error ? error.message : String(error);
 57→}
 58→
 59→export function getCronDispatchSchedule(now: Date): CronDispatchSchedule {
 60→  const hour = now.getUTCHours();
 61→  const minute = now.getUTCMinutes();
 62→  const dayOfWeek = now.getUTCDay();
 63→  const dayOfMonth = now.getUTCDate();
 64→  const isDailyCronWindow = hour === 6 && minute === 0;
 65→
 66→  return {
 67→    weeklySnapshot: isDailyCronWindow && dayOfWeek === 1,
 68→    monthlyRollup: isDailyCronWindow && dayOfMonth === 1,
 69→    dailyRoadSnapshot: isDailyCronWindow,
 70→  };
 71→}
 72→
 73→function resolveCronDispatchInstant(input: string | null): Date | null {
 74→  if (!input) return new Date();
 75→  const parsed = new Date(input);
 76→  if (Number.isNaN(parsed.getTime())) return null;
 77→  return parsed;
 78→}
