 20→const LOCKOUT_MAX_ATTEMPTS = 5;
 21→const LOCKOUT_DURATION_MINUTES = 30;
 22→
 23→function extractRequestIp(request: Request | undefined): string | null {
 24→  if (!request) return null;
 25→  const header =
 26→    request.headers.get("x-vercel-forwarded-for") ??
 27→    request.headers.get("x-forwarded-for") ??
 28→    request.headers.get("x-real-ip");
 29→  const value = header?.split(",")[0]?.trim();
