 37→async function persistLoginFailure(profile: UserProfile | null, request: Request | undefined, userId: string): Promise<void> {
 38→  if (!profile) {
 39→    await logSecurityEvent({
 40→      eventType: "login_failure",
 41→      userId,
 42→      request,
 43→      details: { reason: "invalid_credentials", hasProfile: false },
 44→    });
 45→    return;
 46→  }
 47→
 48→  const nextCount = (profile.failedLoginCount ?? 0) + 1;
 49→  profile.failedLoginCount = nextCount;
 50→  if (nextCount >= LOCKOUT_MAX_ATTEMPTS) {
 51→    profile.lockedUntil = new Date(Date.now() + LOCKOUT_DURATION_MINUTES * 60 * 1000).toISOString();
 52→  }
 53→  await upsertUserProfile(profile.id, profile);
 54→  await logSecurityEvent({
 55→    eventType: nextCount >= LOCKOUT_MAX_ATTEMPTS ? "account_locked" : "login_failure",
 56→    userId: profile.id,
 57→    request,
 58→    details: {
 59→      failedLoginCount: nextCount,
 60→      lockedUntil: profile.lockedUntil ?? null,
 61→    },
 62→  });
 63→}
 64→
 65→async function clearLoginFailure(profile: UserProfile): Promise<void> {
 66→  if (!profile.failedLoginCount && !profile.lockedUntil) return;
 67→  profile.failedLoginCount = 0;
 68→  profile.lockedUntil = null;
 69→  await upsertUserProfile(profile.id, profile);
 70→}
