168→if (googleClientId && googleClientSecret) {
169→  providers.unshift(
170→    Google({
171→      clientId: googleClientId,
172→      clientSecret: googleClientSecret,
173→      token: {
174→        async conform(response) {
175→          // Auth.js v0.33 throws "TODO: Handle OIDC response body error" when
176→          // the token response content-type isn't exactly "application/json".
177→          // Google sometimes returns "application/json; charset=utf-8" which
178→          // triggers this bug. Fix by re-wrapping with a clean content-type.
179→          if (!response.ok) {
180→            const body = await response.text().catch(() => "");
181→            const trimmed = body.length > 1200 ? `${body.slice(0, 1200)}…` : body;
182→            console.error("[auth] google token endpoint response error", {
183→              status: response.status,
184→              statusText: response.statusText,
185→              body: trimmed,
186→            });
187→            return undefined;
188→          }
189→          const contentType = response.headers.get("content-type") ?? "";
190→          if (contentType.includes("application/json")) {
191→            // Re-create response with clean content-type so Auth.js parses it
192→            const body = await response.text();
193→            return new Response(body, {
194→              status: response.status,
195→              headers: { "Content-Type": "application/json" },
196→            });
197→          }
198→          return undefined;
199→        },
200→      },
201→    })
202→  );
203→}
