 36→export class AuthClientError extends Error {
 37→  code: AuthClientErrorCode;
 38→  retryable: boolean;
 39→
 40→  constructor(
 41→    code: AuthClientErrorCode,
 42→    message: string,
 43→    options: { retryable?: boolean; cause?: unknown } = {}
 44→  ) {
 45→    super(message);
 46→    this.name = "AuthClientError";
 47→    this.code = code;
 48→    this.retryable = Boolean(options.retryable);
 49→    if (options.cause !== undefined) {
