 86→type ApiErrorPayload = {
 87→  message: string;
 88→  code?: string;
 89→};
 90→
 91→async function extractResponseErrorPayload(response: Response, fallback: string): Promise<ApiErrorPayload> {
 92→  const contentType = response.headers.get("content-type")?.toLowerCase() ?? "";
 93→  if (contentType.includes("application/json")) {
 94→    const payload = await safeReadJson<{ error?: unknown; message?: unknown; code?: unknown }>(response);
 95→    if (payload) {
 96→      const message = sanitizeErrorMessage(payload.error ?? payload.message, fallback);
 97→      const code = typeof payload.code === "string" && payload.code.trim() ? payload.code.trim() : undefined;
 98→      return { message, code };
 99→    }
100→    return { message: fallback };
101→  }
102→  const text = await response.text().catch(() => "");
103→  return { message: sanitizeErrorMessage(text, fallback) };
104→}
105→
106→function mapAuthJsError(errorType: string | null, errorCode: string | null): AuthClientError {
107→  switch (errorType) {
108→    case "CredentialsSignin":
109→      return new AuthClientError("invalid_credentials", "Invalid phone/email or password.", { retryable: true });
110→    case "Callback":
111→    case "CallbackRouteError":
112→      return new AuthClientError("callback_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
113→    case "Configuration":
114→      return new AuthClientError("configuration_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
115→    case "AccessDenied":
116→      return new AuthClientError("access_denied", "Access denied for this account.");
117→    default:
118→      if (errorCode === "credentials") {
119→        return new AuthClientError("invalid_credentials", "Invalid phone/email or password.", { retryable: true });
120→      }
121→      return new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
122→  }
123→}
124→
125→function toAuthClientError(error: unknown, fallback: string): AuthClientError {
126→  if (error instanceof AuthClientError) return error;
127→  if (error instanceof Error) {
128→    return new AuthClientError("unknown_error", sanitizeErrorMessage(error.message, fallback), { cause: error });
129→  }
130→  return new AuthClientError("unknown_error", fallback);
131→}
