148→async function signInWithCredentialsOnce(identifier: string, password: string): Promise<void> {
149→  const normalizedIdentifier = normalizeIdentifier(identifier)?.value ?? identifier.trim();
150→  const csrfToken = await getCsrfToken();
151→  const body = new URLSearchParams();
152→  body.set("csrfToken", csrfToken);
153→  body.set("identifier", normalizedIdentifier);
154→  body.set("email", normalizedIdentifier);
155→  body.set("password", password);
156→  body.set("callbackUrl", window.location.origin);
157→  body.set("json", "true");
158→
159→  const response = await apiFetch("/api/auth/callback/credentials", {
160→    method: "POST",
161→    headers: {
162→      "Content-Type": "application/x-www-form-urlencoded",
163→      "X-Auth-Return-Redirect": "1",
164→    },
165→    body,
166→  });
167→
168→  if (!response.ok) {
169→    const { message } = await extractResponseErrorPayload(response, DEFAULT_SIGN_IN_ERROR);
170→    const retryable = response.status >= 500;
171→    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
172→  }
173→
174→  const payload = await safeReadJson<AuthRedirectPayload>(response);
175→  if (!payload || typeof payload.url !== "string") {
176→    throw new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
177→  }
178→
179→  let url: URL;
180→  try {
181→    url = new URL(payload.url, window.location.origin);
182→  } catch {
183→    throw new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
184→  }
185→
186→  const errorType = url.searchParams.get("error");
187→  const errorCode = url.searchParams.get("code");
188→  if (errorType || errorCode) {
189→    throw mapAuthJsError(errorType, errorCode);
190→  }
191→}
