193→export async function signInWithCredentials(
194→  identifier: string,
195→  password: string,
196→  options: SignInWithCredentialsOptions = {}
197→): Promise<void> {
198→  const maxAttempts = normalizeAttempts(options.maxAttempts);
199→  const retryDelayMs = normalizeDelayMs(options.retryDelayMs);
200→
201→  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
202→    try {
203→      await signInWithCredentialsOnce(identifier, password);
204→      return;
205→    } catch (error) {
206→      const authError = toAuthClientError(error, DEFAULT_SIGN_IN_ERROR);
207→      const shouldRetry = authError.retryable && attempt < maxAttempts;
208→      if (!shouldRetry) throw authError;
209→      await delay(retryDelayMs);
210→    }
211→  }
212→}
