569→   569→   569→    const result = await query<{ constraint_definition: string | null }>(
570→   570→   570→      `
571→   571→   571→        SELECT pg_get_constraintdef(c.oid) AS constraint_definition
572→   572→   572→        FROM pg_constraint c
573→   573→   573→        JOIN pg_class rel ON rel.oid = c.conrelid
574→   574→   574→        JOIN pg_namespace ns ON ns.oid = rel.relnamespace
