587→   587→   587→    return {
588→   588→   588→      ok: diff.ok,
589→   589→   589→      expected: diff.expected,
590→   590→   590→      actual: diff.actual,
591→   591→   591→      missing: diff.missing,
592→   592→   592→      extra: diff.extra,
593→   593→   593→    };
594→   594→   594→  } catch (error) {
595→   595→   595→    if (isStorageUnavailableError(error)) {
