**File to modify:** `/Users/charlesvictormahouve/Documents/GitHub/africandatalayer/lib/server/userTrust.ts`

**Add function:**

```typescript
export async function adjustTrustOnReview(input: {
  userId: string;
  decision: "approved" | "rejected" | "flagged";
}): Promise<{ trustScore: number; trustTier: TrustTier }> {
  const stats = await query<{ consecutive_clean: number }>(
    `SELECT COUNT(*)::int AS consecutive_clean
     FROM point_events
     WHERE user_id = $1
       AND COALESCE(details->>'reviewDecision', 'approved') = 'approved'
       AND created_at > (
         SELECT COALESCE(MAX(created_at), '1970-01-01')
         FROM point_events
         WHERE user_id = $1
           AND details->>'reviewDecision' = 'rejected'
       )`,
    [input.userId],
  );
  const consecutiveClean = stats.rows[0]?.consecutive_clean ?? 0;

  let delta = 0;
  if (input.decision === "approved") {
    delta = consecutiveClean > 10 ? 2 : 1;
  } else if (input.decision === "rejected") {
    delta = -15;
  } else if (input.decision === "flagged") {
    delta = -5;
  }

  const result = await updateUserTrust({ userId: input.userId, delta });
  return { trustScore: result.trustScore, trustTier: result.trustTier };
}
```

This function would be called from the admin review handler when it is wired up.

